1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	function cellKey([x, y]: Cell): string {
10	  return `${x},${y}`;
11	}
12	
13	function neighborsOf([x, y]: Cell): Cell[] {
14	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	}
16	
17	function countLiveNeighbors(cell: Cell, liveKeys: Set<string>): number {
18	  return neighborsOf(cell).filter((n) => liveKeys.has(cellKey(n))).length;
19	}
20	
21	function willBeLive(cell: Cell, liveKeys: Set<string>): boolean {
22	  const liveNeighbors = countLiveNeighbors(cell, liveKeys);
23	  const wasLive = liveKeys.has(cellKey(cell));
24	  return wasLive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
25	}
26	
27	function candidateCells(cells: Cell[]): Cell[] {
28	  const seen = new Map<string, Cell>();
29	  for (const cell of cells) {
30	    for (const candidate of [cell, ...neighborsOf(cell)]) {
31	      seen.set(cellKey(candidate), candidate);
32	    }
33	  }
34	  return [...seen.values()];
35	}
36	
37	export function nextGeneration(cells: Cell[]): Cell[] {
38	  const liveKeys = new Set(cells.map(cellKey));
39	  return candidateCells(cells).filter((cell) => willBeLive(cell, liveKeys));
40	}
