1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill both cells in a pair with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable as a still life (survival with 3 neighbors)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
21	    // Center cell (1,1) has 4 live neighbors (corners) → dies from overpopulation
22	    const cells: Array<[number, number]> = [[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]];
23	    const result = nextGeneration(cells);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
27	    // L-shape: (0,0), (1,0), (0,1). Dead cell (1,1) has 3 live neighbors → reproduces.
28	    const cells: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
29	    const result = nextGeneration(cells);
30	    expect(result).toContainEqual([1, 1]);
31	  });
32	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
33	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
34	    const result = nextGeneration(vertical);
35	    expect(result).toHaveLength(3);
36	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]] as Array<[number, number]>));
37	  });
38	  it("should handle negative coordinates", () => {
39	    const vertical: Array<[number, number]> = [[-5, -5], [-5, -4], [-5, -3]];
40	    const result = nextGeneration(vertical);
41	    expect(result).toHaveLength(3);
42	    expect(result).toEqual(
43	      expect.arrayContaining([[-6, -4], [-5, -4], [-4, -4]] as Array<[number, number]>),
44	    );
45	  });
